        return Err(
            "bare '.' is not a valid target — use './' to refer to cwd explicitly".into(),
        );
    }

    Err(format!(
        "'{s}' is not a recognized target — expected URL, owner/name shorthand, or path prefix (./X, ../X, /X, ~/X, ~)"
    ))
